import android.content.Context
import android.content.SharedPreferences
import androidx.biometric.BiometricPrompt
import androidx.fragment.app.FragmentActivity
import androidx.lifecycle.Lifecycle

class BiometricAuthManager(context: Context) {
    private val sharedPrefs = context.getSharedPreferences("authenticated", Context.MODE_PRIVATE)

    fun authenticate(activity: FragmentActivity, onSuccess: () -> Unit, onFailure: () -> Unit) {
        // Create a new BiometricPrompt instance
        val prompt = BiometricPrompt(activity, activity.lifecycleOwner, object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                // Handle authentication error
                onFailure()
            }

            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                // Save authenticated flag in SharedPreferences
                sharedPrefs.edit().putBoolean("authenticated", true).apply()
                // Bypass login screen
                onSuccess()
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                // Handle authentication failed
                onFailure()
            }
        })

        // Show biometric prompt to user
        prompt.authenticate(context.getString(R.string.biometric_prompt_title), BiometricPrompt.PromptInfo.Builder().setTitle(R.string.biometric_prompt_subtitle).build())
    }
}